create table dirkspzm32.rep_view_profiles (
    sid                   varchar2(2 char) not null enable,
    firma_nr              number(6, 0) not null enable,
    rep_view_profile_name varchar2(50 char) not null enable,
    rep_id                number(*, 0) not null enable,
    profile_caption       varchar2(100 char) not null enable,
    created_by            varchar2(50 char) not null enable,
    created_date          date not null enable,
    last_change_by        varchar2(50 char),
    last_change_date      date,
    startup_view          varchar2(10 char),
    show_detail_data      varchar2(1 char),
    print_layout_file     varchar2(255 char),
    print_layout_name     varchar2(255 char),
    show_type             number(*, 5),
    chart_setting         varchar2(10 char)
);

alter table dirkspzm32.rep_view_profiles
    add constraint pk_rep_col_cfg_profiles
        primary key ( rep_id,
                      rep_view_profile_name,
                      firma_nr,
                      sid )
            using index enable;


